mapper.select:
select di.id as itemId, di.header_id as depotHeadId, dh.number as billNo, date_format(dh.oper_time, '%Y-%m-%d') as billTimeStr, s.supplier as customerName, m.name as materialName, ifnull(m.standard, '') as standard, ifnull(m.model, '') as model, ifnull(di.batch_number, '') as batchNumber, di.oper_number as operNumber, round(case when mc.weight_editable = '1' and di.weight is not null then di.weight else di.basic_number * ifnull(m.weight, 0) end, 3) as itemWeight, ifnull(m.unit, '') as materialUnit, dp.name as depotName, dh.sales_man as salesMan, dh.remark as remark from jsh_depot_item di left join jsh_depot_head dh on di.header_id = dh.id left join jsh_material m on di.material_id = m.id left join jsh_material_category mc on m.category_id = mc.id left join jsh_supplier s on dh.organ_id = s.id and ifnull(s.delete_flag, '0') != '1' left join jsh_depot dp on di.depot_id = dp.id where di.header_id in
#{hid}
and ifnull(di.delete_flag, '0') != '1' order by di.header_id, di.id

select dh.id as id, dh.number as billNo, date_format(dh.oper_time, '%Y-%m-%d') as billTimeStr, s.supplier as customerName, ifnull(sum(di.all_price), 0) as totalAmount, dh.sales_man as salesMan, dh.remark as remark, GROUP_CONCAT(DISTINCT dp.name SEPARATOR '、') as depotName, GROUP_CONCAT(CONCAT(m.name, ' ', di.oper_number, ifnull(m.unit,''), ' ', round(case when mc.weight_editable = '1' and di.weight is not null then di.weight else di.basic_number * ifnull(m.weight,0) end, 3), '吨') SEPARATOR '、') as materialNames, ifnull(sum(case when mc.weight_editable = '1' and di.weight is not null then di.weight else di.basic_number * ifnull(m.weight, 0) end), 0) as totalWeight from jsh_depot_head dh left join jsh_depot_item di on dh.id = di.header_id and ifnull(di.delete_flag, '0') != '1' left join jsh_material m on di.material_id = m.id left join jsh_material_category mc on m.category_id = mc.id left join jsh_supplier s on dh.organ_id = s.id and ifnull(s.delete_flag, '0') != '1' left join jsh_depot dp on di.depot_id = dp.id where dh.type = '出库' and dh.sub_type = '销售' and dh.status = '1' and ifnull(dh.delete_flag, '0') != '1' and dh.tenant_id = #{tenantId} and dh.id not in (select fi.depot_head_id from jsh_freight_item fi where fi.delete_flag = '0')
and dh.number like #{bindNumber}
group by dh.id, dh.number, dh.oper_time, s.supplier, dh.sales_man, dh.remark order by dh.id desc
